body.script:
                        $(document).ready(function() {
                            // Form validation and submission
                            const form = $('#referralForm');
                            const submitBtn = $('#submitBtn');
                            const submitText = $('#submitText');
                            const submitSpinner = $('#submitSpinner');
                            const messageContainer = $('#messageContainer');

                            // Progress tracking
                            let currentStep = 1;
                            const totalSteps = 4;

                            // File upload handling
                            const fileUploadArea = $('#fileUploadArea');
                            const fileInput = $('#fileInput');
                            const fileList = $('#fileList');
                            let uploadedFiles = [];

                            // File upload area click
                            fileUploadArea.on('click', function() {
                                fileInput.click();
                            });

                            // File input change
                            fileInput.on('change', function(e) {
                                handleFiles(e.target.files);
                            });

                            // Drag and drop functionality
                            fileUploadArea.on('dragover', function(e) {
                                e.preventDefault();
                                fileUploadArea.addClass('dragover');
                            });

                            fileUploadArea.on('dragleave', function(e) {
                                e.preventDefault();
                                fileUploadArea.removeClass('dragover');
                            });

                            fileUploadArea.on('drop', function(e) {
                                e.preventDefault();
                                fileUploadArea.removeClass('dragover');
                                handleFiles(e.originalEvent.dataTransfer.files);
                            });

                            function handleFiles(files) {
                                Array.from(files).forEach(file => {
                                    if (validateFile(file)) {
                                        uploadedFiles.push(file);
                                        displayFile(file);
                                    }
                                });
                            }

                            function validateFile(file) {
                                const maxSize = 10 * 1024 * 1024; // 10MB
                                const allowedTypes = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/jpeg', 'image/jpg', 'image/png'];

                                if (file.size > maxSize) {
                                    showMessage(`File ${file.name} is too large. Maximum size is 10MB.`, 'danger');
                                    return false;
                                }

                                if (!allowedTypes.includes(file.type)) {
                                    showMessage(`File ${file.name} is not supported. Please upload PDF, DOC, DOCX, JPG, or PNG files.`, 'danger');
                                    return false;
                                }

                                return true;
                            }

                            function displayFile(file) {
                                const fileItem = `





                                            ${file.name}
                                            (${formatFileSize(file.size)})





                                `;
                                fileList.append(fileItem);
                            }

                            function formatFileSize(bytes) {
                                if (bytes === 0) return '0 Bytes';
                                const k = 1024;
                                const sizes = ['Bytes', 'KB', 'MB', 'GB'];
                                const i = Math.floor(Math.log(bytes) / Math.log(k));
                                return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
                            }

                            // Remove file
                            $(document).on('click', '.remove-file', function() {
                                const fileName = $(this).data('file');
                                uploadedFiles = uploadedFiles.filter(file => file.name !== fileName);
                                $(this).closest('.alert').remove();
                            });

                            // Form input validation
                            $('input, textarea, select').on('input change', function() {
                                $(this).removeClass('is-invalid');
                                $(this).siblings('.invalid-feedback').remove();
                                updateProgress();
                            });

                            // Update progress based on form completion
                            function updateProgress() {
                                const section1Fields = ['referrer_name', 'referrer_phone'];
                                const section2Fields = ['contact_name', 'email_from', 'phone'];

                                const section1Complete = section1Fields.every(field => $(`#${field}`).val().trim() !== '');
                                const section2Complete = section2Fields.every(field => $(`#${field}`).val().trim() !== '');

                                // Update step indicators
                                updateStepIndicator(1, section1Complete);
                                updateStepIndicator(2, section1Complete && section2Complete);

                                if (section1Complete && section2Complete) {
                                    currentStep = 3;
                                } else if (section1Complete) {
                                    currentStep = 2;
                                } else {
                                    currentStep = 1;
                                }
                            }

                            function updateStepIndicator(stepNumber, completed) {
                                const stepElement = $(`#step${stepNumber}`);
                                if (completed) {
                                    stepElement.removeClass('active').addClass('completed');
                                    stepElement.html('');
                                } else if (stepNumber === currentStep) {
                                    stepElement.addClass('active').removeClass('completed');
                                    stepElement.text(stepNumber);
                                } else {
                                    stepElement.removeClass('active completed');
                                    stepElement.text(stepNumber);
                                }
                            }

                            // Email validation
                            function isValidEmail(email) {
                                const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                                return emailRegex.test(email);
                            }

                            // Phone validation
                            function isValidPhone(phone) {
                                const phoneRegex = /^[+]?[\d\s\-()]{10,}$/;
                                return phoneRegex.test(phone);
                            }

                            // Form submission
                            form.on('submit', function(e) {
                                e.preventDefault();

                                // Clear previous validation errors
                                $('.form-control').removeClass('is-invalid');
                                $('.invalid-feedback').remove();

                                // Validate required fields
                                const requiredFields = [
                                    { id: 'referrer_name', message: 'Please enter your full name' },
                                    { id: 'referrer_phone', message: 'Please enter your phone number' },
                                    { id: 'contact_name', message: 'Please enter the contact\'s full name' },
                                    { id: 'email_from', message: 'Please enter a valid email address' },
                                    { id: 'phone', message: 'Please enter the contact\'s phone number' }
                                ];

                                let isValid = true;
                                let firstInvalidField = null;

                                requiredFields.forEach(field => {
                                    const input = $(`#${field.id}`);
                                    const value = input.val().trim();

                                    if (!value) {
                                        showFieldError(input, field.message);
                                        isValid = false;
                                        if (!firstInvalidField) firstInvalidField = input;
                                    } else if (field.id === 'email_from' && !isValidEmail(value)) {
                                        showFieldError(input, 'Please enter a valid email address');
                                        isValid = false;
                                        if (!firstInvalidField) firstInvalidField = input;
                                    } else if ((field.id === 'referrer_phone' || field.id === 'phone') && !isValidPhone(value)) {
                                        showFieldError(input, 'Please enter a valid phone number');
                                        isValid = false;
                                        if (!firstInvalidField) firstInvalidField = input;
                                    }
                                });

                                if (!isValid) {
                                    showMessage('Please correct the errors in the form.', 'danger');
                                    if (firstInvalidField) {
                                        firstInvalidField.focus();
                                        $('html, body').animate({
                                            scrollTop: firstInvalidField.offset().top - 100
                                        }, 500);
                                    }
                                    return;
                                }

                                // Show loading state
                                submitText.html('Submitting...');
                                submitSpinner.removeClass('d-none');
                                submitBtn.prop('disabled', true);

                                // Collect form data
                                const formData = new FormData(this);
                                const data = {};
                                for (let [key, value] of formData.entries()) {
                                    if (key !== 'files') {
                                        data[key] = value;
                                    }
                                }

                                // Submit via AJAX
                                $.ajax({
                                    url: '/referral/submit',
                                    type: 'POST',
                                    contentType: 'application/json',
                                    data: JSON.stringify(data),
                                    success: function(response) {
                                        if (response.success) {
                                            showMessage('Thank you! Your business lead has been submitted successfully.', 'success');
                                            updateStepIndicator(4, true);

                                            setTimeout(function() {
                                                window.location.href = '/referral/thank-you';
                                            }, 2000);
                                        } else {
                                            showMessage(response.message || 'An error occurred while submitting your lead.', 'danger');
                                        }
                                    },
                                    error: function(xhr) {
                                        const response = xhr.responseJSON || {};
                                        const errorMessage = response.message || 'An error occurred while submitting your lead. Please try again.';
                                        showMessage(errorMessage, 'danger');

                                        // Log detailed error for debugging
                                        console.error('Submission error:', xhr.responseText);
                                    },
                                    complete: function() {
                                        // Reset loading state
                                        submitText.html('Submit Business Lead');
                                        submitSpinner.addClass('d-none');
                                        submitBtn.prop('disabled', false);
                                    }
                                });
                            });

                            function showFieldError(field, message) {
                                field.addClass('is-invalid');
                                if (!field.siblings('.invalid-feedback').length) {
                                    field.after(`
${message}`);
                                }
                            }

                            function showMessage(message, type) {
                                const alertClass = type === 'success' ? 'alert-success' : 
                                                 type === 'danger' ? 'alert-danger' : 'alert-info';
                                const icon = type === 'success' ? 'fa-check-circle' : 
                                           type === 'danger' ? 'fa-exclamation-triangle' : 'fa-info-circle';

                                const messageHtml = `



                                        ${message}


                                `;
                                messageContainer.html(messageHtml);

                                // Auto-hide success messages after 5 seconds
                                if (type === 'success') {
                                    setTimeout(function() {
                                        messageContainer.find('.alert').alert('close');
                                    }, 5000);
                                }
                            }

                            // Initialize progress on page load
                            updateProgress();

                            // Smooth scroll for form sections
                            $('.section-title').on('click', function() {
                                const section = $(this).closest('.form-section');
                                $('html, body').animate({
                                    scrollTop: section.offset().top - 80
                                }, 500);
                            });
                        });
